func (v SpecValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	var sasl basetypes.ObjectValue

	if v.Sasl.IsNull() {
		sasl = types.ObjectNull(
			SaslValue{}.AttributeTypes(ctx),
		)
	}

	if v.Sasl.IsUnknown() {
		sasl = types.ObjectUnknown(
			SaslValue{}.AttributeTypes(ctx),
		)
	}

	if !v.Sasl.IsNull() && !v.Sasl.IsUnknown() {
		sasl = types.ObjectValueMust(
			SaslValue{}.AttributeTypes(ctx),
			v.Sasl.Attributes(),
		)
	}

	var tls basetypes.ObjectValue

	if v.Tls.IsNull() {
		tls = types.ObjectNull(
			TlsValue{}.AttributeTypes(ctx),
		)
	}

	if v.Tls.IsUnknown() {
		tls = types.ObjectUnknown(
			TlsValue{}.AttributeTypes(ctx),
		)
	}

	if !v.Tls.IsNull() && !v.Tls.IsUnknown() {
		tls = types.ObjectValueMust(
			TlsValue{}.AttributeTypes(ctx),
			v.Tls.Attributes(),
		)
	}

	var brokersVal basetypes.ListValue
	switch {
	case v.Brokers.IsUnknown():
		brokersVal = types.ListUnknown(types.StringType)
	case v.Brokers.IsNull():
		brokersVal = types.ListNull(types.StringType)
	default:
		var d diag.Diagnostics
		brokersVal, d = types.ListValue(types.StringType, v.Brokers.Elements())
		diags.Append(d...)
	}

	if diags.HasError() {
		return types.ObjectUnknown(map[string]attr.Type{
			"brokers": basetypes.ListType{
				ElemType: types.StringType,
			},
			"client_name":         basetypes.StringType{},
			"condition":           basetypes.StringType{},
			"data":                basetypes.StringType{},
			"delivery_mode":       basetypes.StringType{},
			"offset_reset_policy": basetypes.StringType{},
			"path":                basetypes.StringType{},
			"sasl": basetypes.ObjectType{
				AttrTypes: SaslValue{}.AttributeTypes(ctx),
			},
			"tls": basetypes.ObjectType{
				AttrTypes: TlsValue{}.AttributeTypes(ctx),
			},
			"topic": basetypes.StringType{},
		}), diags
	}

	attributeTypes := map[string]attr.Type{
		"brokers": basetypes.ListType{
			ElemType: types.StringType,
		},
		"client_name":         basetypes.StringType{},
		"condition":           basetypes.StringType{},
		"data":                basetypes.StringType{},
		"delivery_mode":       basetypes.StringType{},
		"offset_reset_policy": basetypes.StringType{},
		"path":                basetypes.StringType{},
		"sasl": basetypes.ObjectType{
			AttrTypes: SaslValue{}.AttributeTypes(ctx),
		},
		"tls": basetypes.ObjectType{
			AttrTypes: TlsValue{}.AttributeTypes(ctx),
		},
		"topic": basetypes.StringType{},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"brokers":             brokersVal,
			"client_name":         v.ClientName,
			"condition":           v.Condition,
			"data":                v.Data,
			"delivery_mode":       v.DeliveryMode,
			"offset_reset_policy": v.OffsetResetPolicy,
			"path":                v.Path,
			"sasl":                sasl,
			"tls":                 tls,
			"topic":               v.Topic,
		})

	return objVal, diags
}

func (v SpecValue) Equal(o attr.Value) bool {
	other, ok := o.(SpecValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.Brokers.Equal(other.Brokers) {
		return false
	}

	if !v.ClientName.Equal(other.ClientName) {
		return false
	}

	if !v.Condition.Equal(other.Condition) {
		return false
	}

	if !v.Data.Equal(other.Data) {
		return false
	}

	if !v.DeliveryMode.Equal(other.DeliveryMode) {
		return false
	}

	if !v.OffsetResetPolicy.Equal(other.OffsetResetPolicy) {
		return false
	}

	if !v.Path.Equal(other.Path) {
		return false
	}

	if !v.Sasl.Equal(other.Sasl) {
		return false
	}

	if !v.Tls.Equal(other.Tls) {
		return false
	}

	if !v.Topic.Equal(other.Topic) {
		return false
	}

	return true
}

