func NewOffsetsValue(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) (OffsetsValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	// Reference: https://github.com/hashicorp/terraform-plugin-framework/issues/521
	ctx := context.Background()

	for name, attributeType := range attributeTypes {
		attribute, ok := attributes[name]

		if !ok {
			diags.AddError(
				"Missing OffsetsValue Attribute Value",
				"While creating a OffsetsValue value, a missing attribute value was detected. "+
					"A OffsetsValue must contain values for all attributes, even if null or unknown. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("OffsetsValue Attribute Name (%s) Expected Type: %s", name, attributeType.String()),
			)

			continue
		}

		if !attributeType.Equal(attribute.Type(ctx)) {
			diags.AddError(
				"Invalid OffsetsValue Attribute Type",
				"While creating a OffsetsValue value, an invalid attribute value was detected. "+
					"A OffsetsValue must use a matching attribute type for the value. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("OffsetsValue Attribute Name (%s) Expected Type: %s\n", name, attributeType.String())+
					fmt.Sprintf("OffsetsValue Attribute Name (%s) Given Type: %s", name, attribute.Type(ctx)),
			)
		}
	}

	for name := range attributes {
		_, ok := attributeTypes[name]

		if !ok {
			diags.AddError(
				"Extra OffsetsValue Attribute Value",
				"While creating a OffsetsValue value, an extra attribute value was detected. "+
					"A OffsetsValue must not contain values beyond the expected attribute types. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("Extra OffsetsValue Attribute Name: %s", name),
			)
		}
	}

	if diags.HasError() {
		return NewOffsetsValueUnknown(), diags
	}

	offsetAttribute, ok := attributes["offset"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`offset is missing from object`)

		return NewOffsetsValueUnknown(), diags
	}

	offsetVal, ok := offsetAttribute.(basetypes.Int64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`offset expected to be basetypes.Int64Value, was: %T`, offsetAttribute))
	}

	partitionAttribute, ok := attributes["partition"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`partition is missing from object`)

		return NewOffsetsValueUnknown(), diags
	}

	partitionVal, ok := partitionAttribute.(basetypes.Int64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`partition expected to be basetypes.Int64Value, was: %T`, partitionAttribute))
	}

	topicAttribute, ok := attributes["topic"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`topic is missing from object`)

		return NewOffsetsValueUnknown(), diags
	}

	topicVal, ok := topicAttribute.(basetypes.StringValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`topic expected to be basetypes.StringValue, was: %T`, topicAttribute))
	}

	if diags.HasError() {
		return NewOffsetsValueUnknown(), diags
	}

	return OffsetsValue{
		Offset:    offsetVal,
		Partition: partitionVal,
		Topic:     topicVal,
		state:     attr.ValueStateKnown,
	}, diags
}

func NewOffsetsValueMust(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) OffsetsValue {
	object, diags := NewOffsetsValue(attributeTypes, attributes)

	if diags.HasError() {
		// This could potentially be added to the diag package.
		diagsStrings := make([]string, 0, len(diags))

		for _, diagnostic := range diags {
			diagsStrings = append(diagsStrings, fmt.Sprintf(
				"%s | %s | %s",
				diagnostic.Severity(),
				diagnostic.Summary(),
				diagnostic.Detail()))
		}

		panic("NewOffsetsValueMust received error(s): " + strings.Join(diagsStrings, "\n"))
	}

	return object
}

func (t OffsetsType) ValueFromTerraform(ctx context.Context, in tftypes.Value) (attr.Value, error) {
	if in.Type() == nil {
		return NewOffsetsValueNull(), nil
	}

	if !in.Type().Equal(t.TerraformType(ctx)) {
		return nil, fmt.Errorf("expected %s, got %s", t.TerraformType(ctx), in.Type())
	}

	if !in.IsKnown() {
		return NewOffsetsValueUnknown(), nil
	}

	if in.IsNull() {
		return NewOffsetsValueNull(), nil
	}

	attributes := map[string]attr.Value{}

	val := map[string]tftypes.Value{}

	err := in.As(&val)

	if err != nil {
		return nil, err
	}

	for k, v := range val {
		a, err := t.AttrTypes[k].ValueFromTerraform(ctx, v)

		if err != nil {
			return nil, err
		}

		attributes[k] = a
	}

	return NewOffsetsValueMust(OffsetsValue{}.AttributeTypes(ctx), attributes), nil
}

